/**
 * @summary Get available time slots for a date
 */
export const getGetAvailabilityUrl = (params: GetAvailabilityParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/reservations/availability?${stringifiedParams}`
    : `/api/reservations/availability`;
};

export const getAvailability = async (
  params: GetAvailabilityParams,
  options?: RequestInit,
): Promise<AvailabilityResponse> => {
  return customFetch<AvailabilityResponse>(getGetAvailabilityUrl(params), {
    ...options,
    method: "GET",
  });
};

